def test_create_savings_goal_valid_amount(auth_token, api_client, future_date):
    payload = {
        "target_amount": 500.00,
        "target_date": future_date
    }
    resp = api_client.post("/goals", json=payload, headers={"Authorization": f"Bearer {auth_token}"})
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert body.get("goal_id"), "goal_id must be present and non-empty"
    assert body.get("progress") == 0, f"Initial progress must be 0, got {body.get('progress')}"

